var vals=rawData.rows.map(function(r){return r.v;}).sort(function(a,b){return a-b;});
function kde(arr,x,bw){
  var s=0;
  for(var i=0;i<arr.length;i++){
    var u=(x-arr[i])/bw;
    s+=Math.exp(-0.5*u*u);
  }
  return s/(arr.length*bw*Math.sqrt(2*Math.PI));
}
var minV=vals[0],maxV=vals[vals.length-1];
var bw=2;
var densityCurve=[];
var steps=40;
for(var i=0;i<=steps;i++){
  var x=minV+(maxV-minV)*i/steps;
  densityCurve.push([x,kde(vals,x,bw)]);
}
var maxD=0;
densityCurve.forEach(function(d){if(d[1]>maxD)maxD=d[1];});
densityCurve=densityCurve.map(function(d){return [d[0],d[1]/maxD*0.35+0.6];});
var n=vals.length;
function q(f){var p=(n-1)*f;var lo=Math.floor(p);var hi=Math.ceil(p);if(lo===hi)return vals[lo];return vals[lo]*(hi-p)+vals[hi]*(p-lo);}
var median=q(0.5),q1=q(0.25),q3=q(0.75);
var jitter=vals.map(function(v){return [v,0.15+Math.random()*0.25];});
transformedData={density:densityCurve,jitter:jitter,median:median,q1:q1,q3:q3,min:vals[0],max:vals[n-1]};
